    "source_fingerprint": "{\"title\":\"OEFENINGEN\",\"order_index\":10,\"content\":{\"type\":\"exercises\",\"sections\":[{\"title\":\"Oefening I\",\"instruction\":\"Vertaal.\",\"type\":\"translation\",\"items\":[{\"prompt\":\"Hoe laat is het? Mijn bus vertrekt om 11.00 uur.\",\"answer\":\"Jam berapa sekarang? Bus saya berangkat jam sebelas siang.\"},{\"prompt\":\"Is het niet zo dat u vandaag naar Medan vertrekt?\",\"answer\":\"Hari ini Anda berangkat ke Medan, bukan?\"},{\"prompt\":\"Nee, ik ga 's ochtends om 05.10 uur naar het Nationaal Monument.\",\"answer\":\"Tidak, saya pergi jam lima pagi lewat sepuluh ke Monas.\"},{\"prompt\":\"Heb je al gegeten? Het is nu al 20.15 uur!\",\"answer\":\"Kamu sudah makan? Sekarang sudah jam delapan malam lewat seperempat!\"},{\"prompt\":\"Wij hebben vijftien uur in de bus naar Solo gezeten.\",\"answer\":\"Kami duduk lima belas jam di bus ke Solo.\"},{\"prompt\":\"Nee, hij houdt er niet van om met de bus te gaan.\",\"answer\":\"Tidak, dia tidak suka naik bus.\"},{\"prompt\":\"Nee, hij kwam niet naar mijn, maar naar haar huis.\",\"answer\":\"Tidak, dia datang bukan ke rumah saya, tetapi ke rumahnya.\"},{\"prompt\":\"Ga niet zitten! Die kleine, rode stoel is stuk.\",\"answer\":\"Jangan duduk! Kursi kecil yang merah itu rusak.\"},{\"prompt\":\"Vandaag werkt hij tot 21.00 uur.\",\"answer\":\"Hari ini dia bekerja sampai jam sembilan malam.\"},{\"prompt\":\"Vooruit! Zeg maar dat we om 19.45 uur niet kunnen komen!\",\"answer\":\"Ayo! Bilang saja kami tidak bisa datang jam delapan malam kurang seperempat!\"}]},{\"title\":\"Oefening II\",\"instruction\":\"Vertaal.\",\"type\":\"translation\",\"items\":[{\"prompt\":\"Jullie leren nog Indonesisch, is het niet?\",\"answer\":\"Kalian masih belajar bahasa Indonesia, bukan?\"},{\"prompt\":\"Ik wil geen thee drinken. Ik hou van koffie.\",\"answer\":\"Saya tidak mau minum teh. Saya suka kopi.\"},{\"prompt\":\"Deze zeep is niet goed, mijn kleren zijn niet schoon.\",\"answer\":\"Sabun ini tidak bagus, pakaian saya tidak bersih.\"},{\"prompt\":\"Zij weet niet dat haar fiets nog voor het huis staat.\",\"answer\":\"Dia tidak tahu bahwa sepedanya masih di depan rumah.\"},{\"prompt\":\"Dat weet ik niet! Hij is al vertrokken om vijf voor zeven.\",\"answer\":\"Saya tidak tahu! Dia sudah berangkat jam tujuh kurang lima.\"},{\"prompt\":\"Dit is de fiets van mijn vriendin niet!\",\"answer\":\"Ini bukan sepeda teman saya!\"},{\"prompt\":\"Is dit de auto van Krista? Nee, die auto is van ons.\",\"answer\":\"Ini mobil Krista? Tidak, mobil itu mobil kami.\"},{\"prompt\":\"Je bent om 21.30 uur uit Amsterdam gekomen, is 't niet?\",\"answer\":\"Kamu datang dari Amsterdam jam setengah sepuluh malam, 'kan?\"},{\"prompt\":\"Eet niet van dat bord! Het is niet schoon.\",\"answer\":\"Jangan makan dari piring itu! Tidak bersih.\"},{\"prompt\":\"Probeer het bord niet te vullen met water!\",\"answer\":\"Jangan coba mengisi piring itu dengan air!\"}]},{\"title\":\"Oefening III\",\"instruction\":\"Vertaal in het Indonesisch.\",\"type\":\"translation\",\"items\":[{\"prompt\":\"Ga niet slapen, je moet nog eten!\",\"answer\":\"Jangan tidur, kamu harus makan!\"},{\"prompt\":\"Ga zitten en eet!\",\"answer\":\"Duduklah dan makan!\"},{\"prompt\":\"Zeg maar dat wij om ongeveer 10.00 uur vertrekken.\",\"answer\":\"Bilang saja kami berangkat kira-kira jam sepuluh pagi.\"},{\"prompt\":\"Waar vliegen jullie naar toe?\",\"answer\":\"Kalian terbang ke mana?\"},{\"prompt\":\"Wij kunnen proberen om van Medan te vertrekken.\",\"answer\":\"Kami bisa coba berangkat dari Medan.\"},{\"prompt\":\"Vanaf het hotel stappen wij in een taxi.\",\"answer\":\"Dari hotel kami naik taksi.\"},{\"prompt\":\"In welke straat stappen jullie uit?\",\"answer\":\"Di jalan mana kalian turun?\"},{\"prompt\":\"Dat weten wij nog niet.\",\"answer\":\"Kami belum tahu.\"},{\"prompt\":\"Ga niet het grote, witte kantoor binnen.\",\"answer\":\"Jangan masuk kantor besar yang putih!\"},{\"prompt\":\"Pak mijn koffer en loop naar de auto.\",\"answer\":\"Ambil koper saya dan jalan ke mobil.\"},{\"prompt\":\"Wilt u a.u.b. daar betalen?\",\"answer\":\"Silakan bayar di sana.\"},{\"prompt\":\"Hoe laat heeft u een afspraak?\",\"answer\":\"Jam berapa Anda punya janji?\"},{\"prompt\":\"Zij vinden het prettig om 's avonds naar het restaurant te gaan.\",\"answer\":\"Mereka suka pergi ke restoran malam.\"},{\"prompt\":\"Houden jullie er ook van om in de stad te eten?\",\"answer\":\"Kalian juga suka makan di kota?\"},{\"prompt\":\"Neen, wij hebben een groot huis en vinden het prettig om thuis te eten.\",\"answer\":\"Tidak, kami punya rumah besar dan suka makan di rumah.\"}]},{\"title\":\"Oefening IV\",\"instruction\":\"Geef met een volledige Indonesische zin antwoord op de vraag. Voorbeeld: Di mana mobil Pak Trisno? (voor mijn huis) -> Mobil Pak Trisno di depan rumah saya.\",\"type\":\"grammar_drill\",\"items\":[{\"prompt\":\"Di mana buku saya?\",\"answer\":\"op de kast\"},{\"prompt\":\"Di mana sepeda temannya?\",\"answer\":\"achter het grote huis\"},{\"prompt\":\"Mas pulang naik apa?\",\"answer\":\"met die mooie rode auto\"},{\"prompt\":\"Sopir kita mau ke mana?\",\"answer\":\"van de winkel naar ons huis\"},{\"prompt\":\"Ibu Suci tinggal di mana?\",\"answer\":\"naast het grote huis aan de Horlogeweg\"},{\"prompt\":\"Di mana ayahmu?\",\"answer\":\"op het veld aan de linkerkant van dat restaurant\"},{\"prompt\":\"Siapa bilang itu?\",\"answer\":\"ik niet, maar meneer Gunawan\"},{\"prompt\":\"Mas Parto mau ke mana?\",\"answer\":\"naar zijn moeder in de stad\"},{\"prompt\":\"Kenapa saya tidak boleh masuk?\",\"answer\":\"wij gaan nu weg\"},{\"prompt\":\"Jam berapa kami berangkat?\",\"answer\":\"om 14.30 uur\"}]},{\"title\":\"Oefening V -- Klok kijken\",\"instruction\":\"Schrijf de tijden voluit in het Indonesisch. Gebruik ook een term voor het dagdeel.\",\"type\":\"grammar_drill\",\"items\":[{\"prompt\":\"14.00 uur\",\"answer\":\"jam dua siang\"},{\"prompt\":\"09.30 uur\",\"answer\":\"jam setengah sepuluh pagi\"},{\"prompt\":\"07.10 uur\",\"answer\":\"jam tujuh pagi lewat sepuluh (menit)\"},{\"prompt\":\"16.55 uur\",\"answer\":\"jam lima sore kurang lima (menit)\"},{\"prompt\":\"15.00 uur\",\"answer\":\"jam tiga siang\"},{\"prompt\":\"13.45 uur\",\"answer\":\"jam dua siang kurang seperempat\"},{\"prompt\":\"07.30 uur\",\"answer\":\"jam setengah delapan pagi\"},{\"prompt\":\"21.05 uur\",\"answer\":\"jam sembilan malam lewat lima (menit)\"},{\"prompt\":\"08.15 uur\",\"answer\":\"jam delapan pagi lewat seperempat\"},{\"prompt\":\"12.00 uur\",\"answer\":\"jam dua belas siang / pukul dua belas\"},{\"prompt\":\"18.25 uur\",\"answer\":\"jam setengah tujuh malam kurang lima (menit)\"},{\"prompt\":\"06.45 uur\",\"answer\":\"jam tujuh pagi kurang seperempat\"}]}]}}"
